const ENGINE_PROGRESS_STEPS=["Loading players","Calculating HKB","Calculating Statcast","Calculating Breakout Scores","Calculating Dynasty Asset Scores","Updating Roster Pressure","Updating Market Edges","Saving"];function engineProgressHTML(done,total,started,complete=false,error=""){const pct=total?done/total:0,activeStep=complete?ENGINE_PROGRESS_STEPS.length:Math.max(1,Math.min(ENGINE_PROGRESS_STEPS.length-1,Math.floor(pct*(ENGINE_PROGRESS_STEPS.length-1))+1)),elapsed=((Date.now()-(started||Date.now()))/1000).toFixed(1),rows=ENGINE_PROGRESS_STEPS.map((s,i)=>{const doneStep=complete||i<activeStep,mark=doneStep?"&#10003;":i===activeStep?"...":"&middot;",cls=doneStep?"done":i===activeStep?"active":"pending";return`<div class="engine-step ${cls}">${mark} ${esc(s)}...</div>`}).join("");return`<div class="engine-progress"><b>Player Engine</b><div class="engine-steps">${rows}</div>${error?`<div class="engine-error">Failed: ${esc(error)}</div>`:complete?`<div class="engine-complete">Completed in ${elapsed} seconds<br>${total} players processed</div>`:`<div class="engine-complete">Recalculating... ${done} / ${total} players processed</div>`}</div>`}function setEngineStatus(status,html){if(status)status.innerHTML=html}
function masterPlayerEngineFinish(started,opts={}){updatePortfolioScores();masterAssignRanks();waiverAlternativeCache=buildWaiverAlternativeCache();const settings=leagueSettings(),il=ilPlayers(),active=activeReservePlayers();rosterPressureCalcContext={full:il.length>=num(settings.roster?.maxIL,10),activeCount:active.length,limit:num(settings.roster?.maxTotal,33)};(db.players||[]).forEach(p=>{if(isWaiverAvailable(p))masterStoredWaiverScore(p,waiverFinderScore(p));masterStoredMarketEdge(p,marketEdgeAnalysis(p));if(isMine(p))masterStoredRosterPressure(p,rosterPressureDecision(p));p.activationPressureScore=activationPressureForPlayer(p);masterPlayerCanonicalize(p)});console.log("Player Engine scores updated");waiverAlternativeCache=null;rosterPressureCalcContext=null;db.settings=db.settings||{};db.settings.lastCalculationDurationMs=Date.now()-started;db.settings.lastFullRecalculationTimestamp=new Date().toISOString();db.settings.lastPlayerEngineRecalculatedPlayers=(db.players||[]).length;db.settings.lastFailedCalculationError="";db.settings.masterPlayerEngineKey=masterPlayerEngineKey();persistScoreCache();saveMasterPlayers();scoreRecalcPending=false;masterEngineRunning=false;if(opts.manual)setEngineButtonState(false);saveDB(false);renderMetrics();renderPerformanceControls();if(opts.render!==false)renderActiveView();const status=opts.statusEl||document.getElementById("scoreStatus");if(status){const d=new Date(scoreCache.timestamp);status.textContent=`Player Engine recalculated ${d.toLocaleString()}. ${db.players.length} players recalculated in ${db.settings.lastCalculationDurationMs} ms.`}if(currentView()==="help")renderHelpWorkflow();console.log(`Player Engine finished recalculation: ${db.players.length} players in ${db.settings.lastCalculationDurationMs} ms`);if(opts.showToast!==false)toast("Player Engine recalculated")}
function masterPlayerEngineRecalculate(reason="manual",opts={}){if(masterEngineRunning){const status=opts.statusEl||document.getElementById("scoreStatus");if(status)status.textContent="Player Engine is already recalculating...";return}const status=opts.statusEl||document.getElementById("scoreStatus");const players=db.players||[],started=Date.now();console.log(`Player Engine start recalculation (${reason})`);console.log(`Player Engine player count processed: 0 / ${players.length}`);masterEngineRunning=true;scoreRecalcPending=true;if(opts.manual)setEngineButtonState(true);if(status)status.textContent=engineProgressMessage(0,players.length);batchProcess(players,25,p=>masterPlayerEngineScoreOne(p),()=>{try{masterPlayerEngineFinish(started,opts)}catch(e){scoreRecalcPending=false;masterEngineRunning=false;if(opts.manual)setEngineButtonState(false);console.error("Player Engine recalculation failed",e);recordCalculationError(e,"Master Player Engine");renderPerformanceControls();if(status)status.textContent=`Player Engine recalculation failed: ${e.message}`;toast("Player Engine recalculation failed")}},(done,total)=>{console.log(`Player Engine player count processed: ${done} / ${total}`);if(status)status.textContent=engineProgressMessage(done,total)})}
