function managerKey(name){return cleanOwner(name).toLowerCase()}function normalizeManager(m){m=m||{};m.teamName=cleanOwner(m.teamName||m.owner||m.team||"");m.managerName=String(m.managerName||"").trim();m.competitiveWindow=m.competitiveWindow||"Retooling";m.tradeStyle=m.tradeStyle||"";m.hkbReliance=m.hkbReliance||"Medium";m.preferredPlayerTypes=m.preferredPlayerTypes||"";m.favoriteProspects=m.favoriteProspects||"";m.favoriteMLBTeams=m.favoriteMLBTeams||"";m.negotiationNotes=m.negotiationNotes||"";m.communicationStyle=m.communicationStyle||"";m.playersHighlyValue=m.playersHighlyValue||"";m.playersWillingToMove=m.playersWillingToMove||"";m.tradeHistoryNotes=m.tradeHistoryNotes||"";m.lastUpdated=m.lastUpdated||today();return m}function normalizeTrade(t){t=t||{};t.date=String(t.date||today()).slice(0,10);t.type=t.type||"Trade";t.notes=String(t.notes||"");t.source=t.source||"Manual";t.rows=num(t.rows,1);t.movements=(t.movements||[]).map(x=>({to:cleanOwner(x.to||x.receivingTeam||""),from:cleanOwner(x.from||x.sendingTeam||""),players:(x.players||[]).map(p=>String(p).trim()).filter(Boolean)})).filter(x=>x.players.length);t.players=[...new Set([...(t.players||[]),...t.movements.flatMap(x=>x.players)].map(p=>String(p).trim()).filter(Boolean))];t.teams=[...new Set([...(t.teams||[]),...t.movements.flatMap(x=>[x.to,x.from])].map(cleanOwner).filter(x=>x&&x!=="FREE AGENT"))];t.id=t.id||tradeSignature(t);return t}function syncManagersFromOwners(){db.managers=db.managers||[];const seen=new Set(db.managers.map(m=>managerKey(m.teamName)));owners().filter(o=>o!=="FREE AGENT").forEach(o=>{if(!seen.has(managerKey(o))){db.managers.push(normalizeManager({teamName:o}));seen.add(managerKey(o))}});(db.trades||[]).flatMap(t=>t.teams||[]).filter(o=>o&&o!=="FREE AGENT").forEach(o=>{if(!seen.has(managerKey(o))){db.managers.push(normalizeManager({teamName:o,tradeHistoryNotes:"Imported trade history available."}));seen.add(managerKey(o))}})}
