function scoreVersion(){return`${db?.settings?.scoreVersion||"seed"}|league-v1|${JSON.stringify(db?.settings?.leagueSettings||{})}`}
function analysisVersion(){return`${scoreVersion()}|players:${db?.players?.length||0}|managers:${db?.managers?.length||0}|trades:${db?.trades?.length||0}`}
function analysisGet(key){return analysisCache?.views?.[key]||null}
function analysisSet(key,data){analysisCache=analysisCache&&analysisCache.version===analysisVersion()?analysisCache:{version:analysisVersion(),views:{}};analysisCache.views[key]=data;try{localStorage.setItem(ANALYSIS_CACHE_KEY,JSON.stringify(analysisCache))}catch(e){console.warn("analysis cache save failed",e);storageSaveWarning(e)}}
function analysisIsStale(key){const cached=analysisGet(key),importTs=Date.parse(latestImportTimestamp()||"");if(!cached)return false;if(analysisCache?.version!==analysisVersion())return true;return importTs&&num(cached.timestamp)<importTs}
function analysisMatchingKey(key){if(analysisGet(key))return key;return Object.keys(analysisCache?.views||{}).find(k=>k===key||k.startsWith(`${key}:`))||key}
