function applyCachedScores(){if(!cacheIsFresh())return false;let applied=0;(db.players||[]).forEach(p=>{const cached=scoreCache.players?.[scorePlayerKey(p)];if(cached){Object.assign(p,cached);applied++}});return applied>0}
