function workflowStatusText(key){if(key==="backup")return localStorage.getItem(storageKeys().players)||localStorage.getItem(STORAGE_KEY)?"Ready to export":"No local data yet";if(key==="hkb")return snapshotTimestamp(/HarryKnowsBall/i)?"Imported":"HKB import stale or missing";if(key==="statcastHitters")return db.players.some(p=>hasAdvancedMetrics(p)&&!isPitcher(p))?"Imported":"Statcast hitters missing";if(key==="statcastPitchers")return db.players.some(p=>hasAdvancedMetrics(p)&&isPitcher(p))?"Imported":"Statcast pitchers missing";if(key==="engine")return masterPlayerCacheFresh()?"Current":"Player Engine needs recalculation";if(key==="rosterPressure")return analysisGet("rosterPressure")&&!analysisIsStale("rosterPressure")?"Current":"Roster Pressure stale";if(key==="economy")return analysisGet("leagueEconomy")&&!analysisIsStale("leagueEconomy")?"Current":"League Economy stale";if(key==="portfolio")return analysisGet("portfolioOptimizer")&&!analysisIsStale("portfolioOptimizer")?"Current":"Portfolio needs refresh";if(key==="decision")return Object.keys(analysisCache?.views||{}).some(k=>k.startsWith("decisionEngine:"))?"Ready":"Run Decision Engine";if(key==="decide")return"Use current reports";return""}
