const idle=window.requestIdleCallback?cb=>window.requestIdleCallback(cb,{timeout:50}):cb=>setTimeout(()=>cb({timeRemaining:()=>0}),1);
function batchProcess(items,size,onItem,onDone,onProgress,i=0){items=items||[];const end=Math.min(i+size,items.length),batchErrors=[];for(let ix=i;ix<end;ix++){try{onItem(items[ix],ix)}catch(e){batchErrors.push({index:ix,item:items[ix],error:e});console.error("Batch item failed", {index:ix,player:items[ix]?.name||items[ix],error:e})}}if(batchErrors.length)console.warn(`Batch completed with ${batchErrors.length} item error${batchErrors.length===1?"":"s"}`,batchErrors.slice(0,5));if(onProgress)onProgress(end,items.length,batchErrors);if(end<items.length){idle(()=>batchProcess(items,size,onItem,onDone,onProgress,end))}else onDone&&onDone()}
