function calculateMarketEdges(){if(!masterEngineGuard("marketEdgeStatus"))return;const rows=[],players=db.players;["marketBuyRows","marketSellRows","marketHoldRows","marketAvoidRows"].forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML=`<tr><td colspan='11' class='note'>Preparing cached rows 0 / ${players.length} players...</td></tr>`});batchProcess(players,25,p=>rows.push(marketSummaryRow(p,cachedMarketEdge(p))),()=>{analysisSet("marketEdges",{timestamp:Date.now(),rows});resetPage("marketBuyRows");resetPage("marketSellRows");resetPage("marketHoldRows");resetPage("marketAvoidRows");renderMarketEdges();toast("Market Edges prepared from cached players")},(done,total)=>["marketBuyRows","marketSellRows","marketHoldRows","marketAvoidRows"].forEach(id=>{const el=document.getElementById(id);if(el)el.innerHTML=`<tr><td colspan='11' class='note'>Preparing cached rows ${done} / ${total} players...</td></tr>`}))}
function waiverFinderScore(p){const stats=normalizeAdvancedStats(p.advancedStats),m=stats?.metrics||{},age=num(p.age),why=[],risk=[];let score=0;if(isPitcher(p)){const stuff=scaleHigh(m["Stuff+"],80,130),kbb=scaleHigh(m["K-BB %"],0,30),sw=scaleHigh(m["SwStr %"],5,20),csw=scaleHigh(m["CSW %"],22,35),xera=scaleLow(m["xERA"],5.5,2.5),run=scaleLow((num(m["xFIP"])||num(m["SIERA"])),5,3);score=stuff*.22+kbb*.20+sw*.16+csw*.14+xera*.12+run*.08+(age&&age<26?8:0)+(String(p.pos||"").includes("SP")?6:0)+Math.min(8,num(p.breakoutScore)*.08);if(stuff>=65)why.push(`Stuff+ ${m["Stuff+"]}`);if(kbb>=60)why.push(`K-BB ${m["K-BB %"]}%`);if(sw>=60)why.push(`SwStr ${m["SwStr %"]}%`);if(csw>=60)why.push(`CSW ${m["CSW %"]}%`);if(xera>=60)why.push(`xERA ${m["xERA"]}`);if(age&&age<26)why.push("young arm");if(String(p.pos||"").includes("SP"))why.push("SP eligibility");if(num(m["xERA"])>4.5)risk.push("run prevention risk");if(num(m["Stuff+"])&&num(m["Stuff+"])<95)risk.push("below-average Stuff+");if(!stats)risk.push("no advanced pitching stats")}else{const xw=scaleHigh(m["xwOBA"],.280,.430),barrel=scaleHigh(m["Barrel %"],3,18),hard=scaleHigh(m["Hard Hit %"],25,60),chase=scaleLow(m["Chase %"],38,18),bbk=(scaleHigh(m["BB %"],4,16)*.55+scaleLow(m["K %"],32,12)*.45);score=xw*.24+barrel*.20+hard*.18+chase*.14+bbk*.12+(isMultiEligible(p)?6:0)+(age&&age<26?8:0)+Math.min(8,num(p.breakoutScore)*.08);if(xw>=60)why.push(`xwOBA ${m["xwOBA"]}`);if(barrel>=60)why.push(`Barrel ${m["Barrel %"]}%`);if(hard>=60)why.push(`Hard Hit ${m["Hard Hit %"]}%`);if(chase>=60)why.push(`low Chase ${m["Chase %"]}%`);if(bbk>=60)why.push(`BB/K profile ${m["BB %"]||0}%/${m["K %"]||0}%`);if(isMultiEligible(p))why.push("multi-position eligibility");if(age&&age<26)why.push("young hitter");if(num(m["K %"])>30)risk.push("strikeout risk");if(num(m["Chase %"])>35)risk.push("chase risk");if(!stats)risk.push("no advanced hitter stats")}score=Math.round(clamp(score,0,100)*10)/10;if(num(p.risk)>55)risk.push(`risk score ${p.risk}`);if(num(p.hkbValue)<100)risk.push("low current market value");return{score,why:why.length?why:["projection/stat profile watch"],risk:risk.length?risk:["no major model flags"]}}
