function renderWaiverFinder(){const body=document.getElementById("waiverFinderRows");if(!body)return;const cached=analysisGet("waiverFinder");if(!cached){body.innerHTML="<tr><td colspan='9' class='note'>Waiver Finder has not been calculated yet. <button onclick='calculateWaiverFinder()'>Calculate Waiver Finder</button></td></tr>";return}const q=(document.getElementById("wfSearch")?.value||"").toLowerCase(),type=document.getElementById("wfType")?.value||"",ageFilter=document.getElementById("wfAge")?.value||"",scoreFilter=document.getElementById("wfScore")?.value||"",multi=document.getElementById("wfMulti")?.value||"",assetFilter=document.getElementById("wfAssetFilter")?.value||"";let rows=(cached.rows||[]).filter(x=>(!q||[x.p.name,x.p.pos,x.p.owner,x.p.org].join(" ").toLowerCase().includes(q))&&(!type||(type==="pitchers"?x.p.isPitcher:x.p.isHitter))&&(!ageFilter||num(x.p.age)<26)&&(!scoreFilter||x.score>=70)&&(!multi||x.p.isMulti)&&passesAssetFilter(x.p,assetFilter)).sort((a,b)=>b.score-a.score||num(b.p.dynastyAssetScore)-num(a.p.dynastyAssetScore)||num(b.p.hkbValue)-num(a.p.hkbValue));const visible=pageSlice("waiverFinder",rows);body.innerHTML=rows.length?visible.map(x=>`<tr><td><b>${esc(x.p.name)}</b></td><td>${esc(x.p.pos||"")}</td><td>${esc(x.p.age||"")}</td><td>${pill(x.p.owner||"FREE AGENT")}</td><td>${x.p.hkbValue||0}</td><td><b>${x.score}</b></td><td><b>${x.p.dynastyAssetScore||0}</b><br><span class="note">${assetSummary(x.p)}</span></td><td>${(x.why||[]).map(esc).join("; ")}</td><td>${(x.risk||[]).map(esc).join("; ")}</td></tr>`).join("")+paginationRowHTML("waiverFinder",rows.length,9):"<tr><td colspan='9' class='note'>No cached waiver breakout candidates match the current filters.</td></tr>"}
function calculateWaiverFinder(){if(!masterEngineGuard("waiverFinderStatus"))return;const body=document.getElementById("waiverFinderRows"),players=db.players.filter(isWaiverAvailable),rows=[];if(body)body.innerHTML=`<tr><td colspan='9' class='note'>Preparing cached rows 0 / ${players.length} players...</td></tr>`;batchProcess(players,25,p=>rows.push(waiverFinderSummaryRow(p,{score:num(p.waiverFinderScore),why:p.waiverFinderWhy||["Using cached Master Player Engine values."],risk:p.waiverFinderRisk||["Use Recalculate Player Engine to refresh risks."]})),()=>{analysisSet("waiverFinder",{timestamp:Date.now(),rows});resetPage("waiverFinder");renderWaiverFinder();toast("Waiver Finder prepared from cached players")},(done,total)=>{if(body)body.innerHTML=`<tr><td colspan='9' class='note'>Preparing cached rows ${done} / ${total} players...</td></tr>`})}
function playerTrend(p){return(db.trends||[]).find(t=>String(t.name).toLowerCase()===String(p.name).toLowerCase())||null}
function isMinorLeague(p){const text=[p.level,p.status,p.rosterStatus,p.org,p.notes].join(" ").toLowerCase();return/(milb|minor|minors|aaa|aa|a\+|single-a|high-a|low-a|rookie|complex|dsl)/.test(text)}
function samePosition(p,c){const ps=String(p.pos||"").split(/[\\/,\s]+/).filter(Boolean),cs=String(c.pos||"").split(/[\\/,\s]+/).filter(Boolean);return ps.some(x=>cs.includes(x))}
function buildWaiverAlternativeCache(){const map={},candidates=db.players.filter(isWaiverAvailable).sort((a,b)=>num(b.hkbValue)-num(a.hkbValue)||num(b.breakoutScore)-num(a.breakoutScore)).slice(0,160).map(p=>({p,...waiverFinderScore(p)}));candidates.forEach(x=>posList(x.p).forEach(pos=>{if(!map[pos]||x.score>map[pos].score)map[pos]=x}));return map}
function bestWaiverAlternative(p){if(waiverAlternativeCache){return posList(p).map(pos=>waiverAlternativeCache[pos]).filter(Boolean).sort((a,b)=>b.score-a.score||num(b.p.hkbValue)-num(a.p.hkbValue))[0]||null}return db.players.filter(x=>x!==p&&isWaiverAvailable(x)&&samePosition(p,x)).sort((a,b)=>num(b.waiverFinderScore)-num(a.waiverFinderScore)||num(b.hkbValue)-num(a.hkbValue)).slice(0,80).map(x=>({p:x,score:num(x.waiverFinderScore),why:x.waiverFinderWhy||["Using cached Master Player Engine values."],risk:x.waiverFinderRisk||[]})).sort((a,b)=>b.score-a.score||num(b.p.hkbValue)-num(a.p.hkbValue))[0]||null}
function redundantPositionPenalty(p){const mine=myPlayers().filter(x=>x!==p&&samePosition(p,x));if(!mine.length)return 0;const better=mine.filter(x=>num(x.gmScore)>num(p.gmScore)+4||num(x.hkbValue)>num(p.hkbValue)+500).length;return Math.min(14,better*4)}
function rosterPressureDecision(p){const trend=playerTrend(p),adv=num(p.advancedBreakoutSignal),age=num(p.age),alt=bestWaiverAlternative(p),keep=[],trade=[],cut=[];let score=32;if(trend?.label==="Falling"||trend?.label==="Lost Value"){score+=18;trade.push(`trend is ${trend.label}`);cut.push(`recent value movement is negative (${trend.hkbDelta>=0?"+":""}${trend.hkbDelta} HKB)`)}if(trend?.label==="Rising"||trend?.label==="New Asset"){score-=14;keep.push(`trend is ${trend.label}`)}if(num(p.hkbValue)<500){score+=14;cut.push("low HKB market value")}else if(num(p.hkbValue)>=3000){score-=24;keep.push("high HKB value anchors the roster spot")}else if(num(p.hkbValue)>=1500){score-=10;trade.push("enough HKB value to shop instead of dropping")}if(adv){if(adv>=75){score-=16;keep.push(`elite advanced breakout signal ${adv}`)}else if(adv<35){score+=12;cut.push(`weak advanced breakout signal ${adv}`)}}if(!adv)score+=3;if(age&&age>=31&&num(p.futureValue)<num(p.currentValue)){score+=15;trade.push("older player with declining future value");cut.push("age curve adds replacement risk")}if(age&&age<25){score-=16;keep.push("young age protects upside")}if(isMultiEligible(p)){score-=8;keep.push("multi-position eligibility adds roster flexibility")}const red=redundantPositionPenalty(p);if(red){score+=red;trade.push("position is redundant on your roster")}if(num(p.currentSkill)<65&&num(p.hkbValue)<700){score+=12;cut.push("bench-only or low-impact profile")}if(num(p.breakoutScore)>=70||num(p.catalyst)>=70){score-=10;keep.push("prospect/upside indicators are still strong")}if(alt&&alt.score>num(p.breakoutScore)+8){score+=16;cut.push(`${alt.p.name} is a stronger free-agent breakout alternative (${alt.score})`)}if(num(p.risk)>60){score+=8;cut.push(`risk score ${p.risk}`)}if(num(p.tradeValue)>=55&&score>=42)trade.push("packageable value remains before cutting");score=Math.round(clamp(score,0,100)*10)/10;let bucket="Watchlist",action="Monitor";if(score<=24||num(p.hkbValue)>=3000)bucket="Core Holds",action="Hold";else if(score<=47)bucket="Trade Chips",action=num(p.tradeValue)>=45?"Shop":"Package";else if(score<=66)bucket="Replaceable",action="Package";else bucket="Cut Candidates",action="Drop";if(bucket==="Watchlist")action="Monitor";if(bucket==="Trade Chips"&&score<=38&&num(p.hkbValue)<1500){bucket="Watchlist";action="Monitor"}if(!keep.length)keep.push("no clear long-term hold signal");if(!trade.length)trade.push("limited market signal unless included in a package");if(!cut.length)cut.push("no urgent cut trigger");return{score,bucket,action,keep,trade,cut,trend,alt}}
const rosterPressureDecisionBase=rosterPressureDecision;
rosterPressureDecision=function(p){const x=rosterPressureDecisionBase(p),add=activationPressureForPlayer(p);if(add){x.score=statScore(x.score+add);x.cut=[`IL activation pressure adds ${add} points`,...x.cut];x.trade=[`future roster crunch makes this roster spot more tradeable`,...x.trade];if(x.score>66){x.bucket="Cut Candidates";x.action="Drop"}else if(x.score>47){x.bucket="Replaceable";x.action="Package"}}return x}
function pitcherPressureProtection(p,x){const pv=pitcherValueEngine(p),isSP=hasPos(p,"SP"),isRP=hasPos(p,"RP")&&!isSP;if(!x||(!isSP&&!isRP)||pv.role<58)return x;const protectedArm=pv.role>=66||(isSP&&pv.role>=62)||(isRP&&(pv.role>=60||/closer|save|hold|setup|leverage/i.test([p.notes,p.recommendation,p.status,p.assetClass].join(" "))));if(!protectedArm)return x;const label=isSP?(pv.role>=70?"Long-Term Hold":"Championship Utility"):(pv.roleLabel==="Volatile RP"?"Volatile RP":pv.role>=72?"Win-Now Asset":pv.role>=64?"Championship Utility":"Trade to Contender");x.score=Math.min(num(x.score),label==="Volatile RP"?54:label==="Trade to Contender"?48:36);x.bucket=label;x.action=label==="Trade to Contender"?"Shop":label==="Volatile RP"?"Monitor":"Hold";x.keep=[...new Set([...(pv.reasons||[]),...x.keep])].slice(0,5);x.trade=[`Pitcher role label: ${label}`,...x.trade.filter(Boolean)].slice(0,5);x.cut=["Do not cut: Reddit Phanatics pitcher role has weekly value.",...x.cut.filter(c=>!/drop|cut candidate|low hkb market value/i.test(c))].slice(0,4);return x}
const rosterPressureDecisionWithIL=rosterPressureDecision;
rosterPressureDecision=function(p){return pitcherPressureProtection(p,rosterPressureDecisionWithIL(p))}
function ilCrunchHTML(){const ctx=ilContext(),cuts=ctx.cuts;const line=(n,label)=>cuts.slice(0,n).map((x,i)=>`<div class="cardline"><b>${i+1}. ${esc(x.p.name)}</b> ${pill(x.bucket)}<br><span class="note">Pressure ${x.score} • Asset ${x.p.dynastyAssetScore||0} • HKB ${x.p.hkbValue||0} • ${esc(x.action)}</span></div>`).join("")||"<p class='note'>No active/reserve cut candidates found.</p>";return`<div class="two"><div><h3>If 1 IL Player Returns</h3>${line(1)}</div><div><h3>If 2 IL Players Return</h3>${line(2)}</div></div><h3>3+ Returning IL Players</h3>${line(Math.max(3,cuts.length))}`}
function renderILPressureCards(){const ctx=ilContext(),cards=document.getElementById("ilPressureCards"),forecast=document.getElementById("ilCrunchForecast");if(cards)cards.innerHTML=marketCard("IL Usage",{p:{name:`${ctx.used}/${ctx.max}`}},()=>`${ctx.full?"Full IL capacity":"Open IL capacity"} • IL does not count toward active/reserve limits`)+marketCard("Activation Pressure",{p:{name:ctx.pressure}},()=>`Active/reserve ${ctx.activeCount}/${ctx.limit} • Low-value bench ${ctx.lowBench}`)+marketCard("Likely First Cut",ctx.cuts[0],x=>`Pressure ${x.score} • ${x.action} • ${x.p.hkbValue||0} HKB`)+marketCard("Likely First 2 Cuts",ctx.cuts[1],x=>`${ctx.cuts.slice(0,2).map(c=>c.p.name).join(" + ")}`);if(forecast)forecast.innerHTML=ilCrunchHTML()}
function rosterPressureSummaryRow(p,x){return{name:p.name,pos:p.pos||"",age:p.age||"",owner:p.owner||"",org:p.org||"",status:isMinorLeague(p)?"Minors":"MLB",isMinor:isMinorLeague(p),isPitcher:isPitcher(p),isHitter:isHitter(p),hkbValue:num(p.hkbValue),dynastyAssetScore:num(p.dynastyAssetScore),tradeLiquidityScore:num(p.tradeLiquidityScore),marketAppreciationScore:num(p.marketAppreciationScore),dynastyRiskScore:num(p.dynastyRiskScore),portfolioFitScore:num(p.portfolioFitScore),portfolioAdjustedAssetScore:num(p.portfolioAdjustedAssetScore),marginalAssetUtility:num(p.marginalAssetUtility),portfolioReason:(p.portfolioFitReasons||[])[0]||"portfolio context neutral",score:num(x.score),bucket:x.bucket,action:x.action,keep:(x.keep||[]).slice(0,3),trade:(x.trade||[]).slice(0,3),cut:(x.cut||[]).slice(0,3)}}
function rosterPressureSummaryCards(rows){const s=leagueSettings(),maxIL=num(s.roster?.maxIL,10),limit=num(s.roster?.maxTotal,33),il=ilPlayers(),active=activeReservePlayers(),full=il.length>=maxIL,lowBench=rows.filter(x=>!x.isMinor&&(x.dynastyAssetScore<55||x.bucket==="Replaceable"||x.bucket==="Cut Candidates")).length,pressure=statScore(35+(il.length/Math.max(1,maxIL))*28+(full?18:0)+Math.max(0,active.length-limit+3)*9+lowBench*2.2),cuts=[...rows].filter(x=>!x.isMinor).sort((a,b)=>b.score-a.score||num(a.dynastyAssetScore)-num(b.dynastyAssetScore)||num(a.hkbValue)-num(b.hkbValue));const card=(title,name,detail)=>`<div class="metric"><div class="lab">${title}</div><div class="num edge-card-name">${esc(name||"None")}</div><div class="note">${esc(detail||"")}</div></div>`;const cardsHTML=card("IL Usage",`${il.length}/${maxIL}`,`${full?"Full IL capacity":"Open IL capacity"} • IL does not count toward active/reserve limits`)+card("Activation Pressure",pressure,`Active/reserve ${active.length}/${limit} • Low-value bench ${lowBench}`)+card("Likely First Cut",cuts[0]?.name||"None",cuts[0]?`Pressure ${cuts[0].score} • ${cuts[0].action} • ${cuts[0].hkbValue||0} HKB`:"No active/reserve cut candidates found.")+card("Likely First 2 Cuts",cuts[1]?.name||"None",cuts.slice(0,2).map(c=>c.name).join(" + ")||"No second cut candidate found.");const line=n=>cuts.slice(0,n).map((x,i)=>`<div class="cardline"><b>${i+1}. ${esc(x.name)}</b> ${pill(x.bucket)}<br><span class="note">Pressure ${x.score} • Asset ${x.dynastyAssetScore||0} • HKB ${x.hkbValue||0} • ${esc(x.action)}</span></div>`).join("")||"<p class='note'>No active/reserve cut candidates found.</p>";const forecastHTML=`<div class="two"><div><h3>If 1 IL Player Returns</h3>${line(1)}</div><div><h3>If 2 IL Players Return</h3>${line(2)}</div></div><h3>3+ Returning IL Players</h3>${line(Math.max(3,cuts.length))}`;return{cardsHTML,forecastHTML}}
