function inferAdvancedType(hitter,pitcher,pos){const pitcherCount=Object.keys(pitcher).length,hitterCount=Object.keys(hitter).length;if(pitcherCount>hitterCount)return"pitcher";if(hitterCount>pitcherCount)return"hitter";return String(pos||"").includes("P")?"pitcher":"hitter"}
