function portfolioStrengths(m){const s=[];if(m.depth.find(d=>d.pos==="OF")?.elite>=2)s.push("Elite OF core");if(m.depth.find(d=>d.pos==="SP")?.elite>=2||m.depth.find(d=>d.pos==="SP")?.score>=72)s.push("Young ace foundation");if(m.liquidity>=70)s.push("Excellent trade liquidity");if(m.pipeline>=68)s.push("Deep farm and prospect pipeline");if(m.scarcity>=68)s.push("Strong scarcity-position foundation");if(m.reliability>=68)s.push("Reliable weekly scoring base");if(m.ctx.used&&m.ctx.used<m.ctx.max)s.push("IL room remains manageable");return s.length?s:["Balanced roster base with no single dominant strength yet"]}
function portfolioWeaknesses(m){const w=[];["C","2B","SS","SP","RP"].forEach(pos=>{const d=m.depth.find(x=>x.pos===pos);if(d&&d.score<55)w.push(`${pos} depth is below contender standard`)});const of=m.depth.find(d=>d.pos==="OF");if(of&&of.count>=8&&of.score<68)w.push("Too many replaceable OF profiles");if(m.depth.find(d=>d.pos==="C")?.count<2)w.push("No catching depth");if(m.depth.find(d=>d.pos==="SP")?.near<2&&m.depth.find(d=>d.pos==="SP")?.score<68)w.push("Insufficient MLB-ready pitching");if(m.ctx.pressure>=65)w.push("Activation pressure could force low-value cuts");if(m.risk>=65)w.push("Risk concentration is high");return w.length?w:["No critical weakness is currently dominating the portfolio"]}
function portfolioBottlenecks(m){const items=[];m.depth.forEach(d=>{if(d.score<60)items.push({title:`Upgrade ${d.pos} depth`,impact:Math.round(72-d.score),why:`${d.pos} portfolio score is ${d.score} with ${d.count} players and ${d.elite} elite assets.`})});if(m.ctx.pressure>=55)items.push({title:"Reduce activation pressure",impact:Math.round(m.ctx.pressure),why:`IL usage is ${m.ctx.used}/${m.ctx.max}; consolidation protects future roster choices.`});if(m.risk>=58)items.push({title:"Lower risk concentration",impact:Math.round(m.risk),why:"Too much core value carries elevated dynasty risk."});if(m.liquidity<58)items.push({title:"Improve trade liquidity",impact:Math.round(70-m.liquidity),why:"More movable assets would open consolidation paths."});if(m.pipeline<58)items.push({title:"Replenish prospect pipeline",impact:Math.round(70-m.pipeline),why:"The farm is not adding enough future surplus."});if(m.reliability<58)items.push({title:"Raise weekly reliability",impact:Math.round(70-m.reliability),why:"Weekly scoring stability is below a strong playoff profile."});return items.sort((a,b)=>b.impact-a.impact).slice(0,10)}
function portfolioActionLists(m){const mine=m.mine,others=db.players.filter(p=>!isMine(p)&&!isFA(p)),fa=db.players.filter(isWaiverAvailable),needs=m.depth.filter(d=>d.score<62).map(d=>d.pos),acquire=others.filter(p=>needs.includes(portfolioPosKey(p))||num(p.marginalAssetUtility)>=68).sort((a,b)=>num(b.marginalAssetUtility)-num(a.marginalAssetUtility)||num(b.dynastyAssetScore)-num(a.dynastyAssetScore)).slice(0,8).map(portfolioPlayerRow),sell=mine.filter(p=>num(p.dynastyRiskScore)>=62||num(p.rosterPressureScore)>=50||portfolioPosKey(p)==="OF"&&m.depth.find(d=>d.pos==="OF")?.count>=8).sort((a,b)=>num(b.rosterPressureScore)-num(a.rosterPressureScore)||num(b.hkbValue)-num(a.hkbValue)).slice(0,8).map(portfolioPlayerRow),hold=mine.sort((a,b)=>num(b.marginalAssetUtility)-num(a.marginalAssetUtility)||num(b.dynastyAssetScore)-num(a.dynastyAssetScore)).slice(0,8).map(portfolioPlayerRow),pack=mine.filter(p=>num(p.hkbValue)>=400&&num(p.dynastyAssetScore)<72&&num(p.marginalAssetUtility)<62).sort((a,b)=>num(b.tradeLiquidityScore)-num(a.tradeLiquidityScore)||num(b.hkbValue)-num(a.hkbValue)).slice(0,8).map(portfolioPlayerRow),waivers=fa.sort((a,b)=>num(b.breakoutScore)-num(a.breakoutScore)||num(b.portfolioFitScore)-num(a.portfolioFitScore)).slice(0,8).map(portfolioPlayerRow),draft=needs.length?needs:["SP","C","SS"],trade=needs.map(pos=>`Consolidate surplus into a ${pos} upgrade`).concat(m.ctx.pressure>=60?["Prioritize 2-for-1 or 3-for-1 consolidation before IL activations"]:[]).slice(0,8);return{acquire,sell,hold,pack,waivers,draft,trade}}
function portfolioOpportunityCost(m,actions){const hold=actions.hold[0],ace=db.players.filter(p=>!isMine(p)&&hasPos(p,"SP")).sort((a,b)=>num(b.marginalAssetUtility)-num(a.marginalAssetUtility)||num(b.dynastyAssetScore)-num(a.dynastyAssetScore))[0],cost=[];if(hold)cost.push(`Trading ${hold.name} costs about ${(hold.mau/12).toFixed(1)} future WAR-equivalent and ${Math.round(hold.champ/10)} championship utility points.`);if(ace)cost.push(`Acquiring another ace like ${ace.name} could raise three-year championship probability by ${Math.max(2,Math.round(num(ace.marginalAssetUtility)/12))}%.`);if(m.ctx.pressure>=60)cost.push(`A consolidation trade could reduce activation pressure by ${Math.round(m.ctx.pressure/8)} roster-crunch points.`);if(actions.pack.length>=2)cost.push(`Packaging ${actions.pack[0].name} + ${actions.pack[1].name} preserves core value while converting depth into ceiling.`);return cost}
function portfolioRoadmap(m,actions,bottlenecks){const next=bottlenecks[0]?.title||"Maintain current core and monitor market prices",three=[next,actions.trade[0]||"Search for one scarce-position upgrade",actions.pack.length>=2?`Package ${actions.pack[0].name} + ${actions.pack[1].name} for one higher-impact asset`:"Keep dry powder for midseason opportunity"].filter(Boolean),offseason=[`Audit ${m.depth.filter(d=>d.score<62).map(d=>d.pos).join(", ")||"bench"} depth`,m.pipeline<65?"Add two high-upside prospects":"Protect the strongest prospect pipeline pieces",m.liquidity<65?"Add liquidity through movable mid-tier assets":"Use liquidity to chase scarce impact"].slice(0,3),draft=(actions.draft||[]).map(pos=>`Prioritize ${pos} with early draft capital`).slice(0,4),vision=m.window==="Win Now"?"Push chips toward SP/RP reliability while preserving one young core tier.":m.window==="Emerging Contender"?"Consolidate depth into scarce stars and arrive as a multi-year contender.":m.window==="Fringe Playoff"?"Turn redundancy into impact and avoid speculative adds that worsen roster pressure.":m.window==="Retooling"?"Hold young appreciation assets, sell fragile veterans, and build toward the next window.":"Accumulate scarce young assets and future surplus before buying veterans.";return{next,three,offseason,draft,vision}}
function buildPortfolioOptimizer(){const m=portfolioOrgMetrics(),strengths=portfolioStrengths(m),weaknesses=portfolioWeaknesses(m),bottlenecks=portfolioBottlenecks(m),actions=portfolioActionLists(m),opportunity=portfolioOpportunityCost(m,actions),roadmap=portfolioRoadmap(m,actions,bottlenecks),metrics={score:m.score,grade:m.grade,window:m.window,title2026:m.title2026,title2027:m.title2027,three:m.three,five:m.five,championshipImpact:m.champ,pipeline:m.pipeline,liquidity:m.liquidity,reliability:m.reliability,activationPressure:m.ctx.pressure,ilUsage:`${m.ctx.used}/${m.ctx.max}`,activeReserve:`${m.ctx.activeCount}/${m.ctx.limit}`};return{timestamp:Date.now(),metrics,strengths,weaknesses,bottlenecks,actions,opportunity,roadmap,depth:m.depth}}
