function teamSummary(){return owners().filter(o=>o!=="FREE AGENT").map(o=>{const ps=db.players.filter(p=>cleanOwner(p.owner)===o);const top=[...ps].sort((a,b)=>b.gmScore-a.gmScore).slice(0,20);const avg=ps.length?ps.reduce((a,p)=>a+p.gmScore,0)/ps.length:0;const power=top.reduce((a,p)=>a+p.gmScore,0);const farm=ps.filter(p=>num(p.age)&&num(p.age)<25).reduce((a,p)=>a+p.futureValue,0);return{owner:o,count:ps.length,avg:Math.round(avg*10)/10,power:Math.round(power),farm:Math.round(farm),blue:ps.filter(p=>p.assetClass==="Blue Chip").length,players:ps}}).sort((a,b)=>b.power-a.power)}
function renderTeams(){if(!ensureScoresForView("teams"))return;const ranks=teamSummary();const el=document.getElementById("teamRanks");if(el)el.innerHTML=ranks.map((t,i)=>`<div class="cardline"><b>${i+1}. ${esc(t.owner)}</b><br><span class="note">Power ${t.power} • Avg ${t.avg} • Blue Chips ${t.blue} • Farm ${t.farm} • Players ${t.count}</span></div>`).join("");const sel=document.getElementById("teamSelect")?.value||ranks[0]?.owner;const team=ranks.find(t=>t.owner===sel)||ranks[0];const det=document.getElementById("teamDetail");if(det)det.innerHTML=team?`<h3>${esc(team.owner)}</h3><p class="note">Power ${team.power} • Avg GM ${team.avg} • Farm ${team.farm}</p><h4>Top assets</h4>${team.players.sort((a,b)=>b.gmScore-a.gmScore).slice(0,12).map((p,i)=>line(p,i+1)).join("")}`:"<p class='note'>Import a league file first.</p>";applyBarWidths()}
