function fillTradeSide(side){const owner=document.getElementById("tradeOwner"+side).value;const names=db.players.filter(p=>cleanOwner(p.owner)===owner).sort((a,b)=>b.tradeValue-a.tradeValue).slice(0,8).map(p=>p.name).join("\n");document.getElementById("trade"+side).value=names}
function tradeList(txt){return txt.split(/\n|,/).map(x=>x.trim()).filter(Boolean).map(n=>db.players.find(p=>p.name.toLowerCase()===n.toLowerCase())||{name:n,gmScore:0,tradeValue:0,futureValue:0,currentValue:0,risk:50,hkbValue:0})}
