function decisionILItems(mode,w){const ctx=ilContext(),items=[];if(!ctx.used)return items;const cuts=ctx.cuts.slice(0,3),names=cuts.map(x=>x.p.name);if(ctx.full&&cuts.length>=2){items.push(decisionItem("Package",`Package ${names.slice(0,2).join(" + ")} into one stronger asset before IL activations.`,cuts.map(x=>x.p),ctx.pressure+18,ctx.pressure*.45,6,[`IL is full at ${ctx.used}/${ctx.max}`,`active/reserve roster is ${ctx.activeCount}/${ctx.limit}`,`likely activation cuts: ${names.join(", ")}`,"2-for-1 or 3-for-1 consolidation reduces future roster crunch"],["requires a manager who wants depth","do not dilute a core asset just to clear a roster spot"],[`Activation Pressure ${ctx.pressure}`,`IL Usage ${ctx.used}/${ctx.max}`]))}const topWaiver=db.players.filter(isWaiverAvailable).map(p=>({p,score:num(p.waiverFinderScore)})).sort((a,b)=>b.score-a.score)[0],cut=cuts[0];if(ctx.full&&topWaiver&&cut&&topWaiver.score<num(cut.score)+8){items.push(decisionItem("Monitor",`Do not add speculative free agents unless they clearly beat ${cut.p.name}.`,[topWaiver.p,cut.p],ctx.pressure+8,4,0,[`IL is full at ${ctx.used}/${ctx.max}`,`top waiver score ${topWaiver.score} does not clearly beat cut pressure ${cut.score}`,`adding a free agent increases activation crunch unless the upgrade is obvious`],["passing on a breakout candidate can sting if new information changes quickly"],[`Top Waiver ${topWaiver.score}`,`Cut Candidate ${cut.score}`,`Activation Pressure ${ctx.pressure}`]))}return items}
