function tradeAnalysisKey(){return`trade:${(document.getElementById("tradeA")?.value||"").trim().toLowerCase()}=>${(document.getElementById("tradeB")?.value||"").trim().toLowerCase()}|${document.getElementById("tradeManager")?.value||""}`}
function analyzeTradeDetailed(){const out=document.getElementById("tradeResult"),cached=analysisGet(tradeAnalysisKey());if(cached?.html){out.innerHTML=cached.html;return}const A=tradeList(document.getElementById("tradeA").value),B=tradeList(document.getElementById("tradeB").value);const sum=(arr,k)=>arr.reduce((a,p)=>a+num(p[k]),0);const delta=sum(B,"tradeValue")-sum(A,"tradeValue"),gm=sum(B,"gmScore")-sum(A,"gmScore"),hkb=sum(B,"hkbValue")-sum(A,"hkbValue"),risk=sum(B,"risk")-sum(A,"risk"),breakout=sum(B,"breakoutScore")-sum(A,"breakoutScore"),portfolio=sum(B,"portfolioAdjustedAssetScore")-sum(A,"portfolioAdjustedAssetScore"),fitDelta=sum(B,"portfolioFitScore")-sum(A,"portfolioFitScore"),mauDelta=sum(B,"marginalAssetUtility")-sum(A,"marginalAssetUtility"),leagueDelta=sum(B,"marginalPositionalAdvantage")-sum(A,"marginalPositionalAdvantage");let verdict=portfolio>8?"Portfolio fit likes this deal.":delta>8?"Take it if roster construction works.":portfolio<-8?"Portfolio fit says ask for a better roster match.":delta<-8?"Ask for more value.":"Fair zone. Let roster fit decide.";const m=managerByTeam(document.getElementById("tradeManager")?.value||"");const fit=m?evaluateManagerFit(m,A,B,-delta):"<p>Select an opposing manager profile to see Manager Fit Score.</p>",sim=tradeImpactSimulator(A,B),crunch=tradeCrunchImpactHTML(A,B),html=`<p><b>${verdict}</b></p><p>Trade value change: <b>${delta.toFixed(1)}</b><br>Portfolio adjusted asset change: <b>${portfolio.toFixed(1)}</b><br>Portfolio fit change: <b>${fitDelta.toFixed(1)}</b><br>Marginal utility change: <b>${mauDelta.toFixed(1)}</b><br>Reddit Phanatics positional edge change: <b>${leagueDelta.toFixed(1)}</b><br>GM score change: <b>${gm.toFixed(1)}</b><br>Breakout score change: <b>${breakout.toFixed(0)}</b><br>HKB change: <b>${hkb.toFixed(0)}</b><br>Risk change: <b>${risk.toFixed(0)}</b></p><p><b>You send:</b> ${A.map(p=>esc(p.name)).join(", ")||"None"}</p><p><b>You receive:</b> ${B.map(p=>esc(p.name)).join(", ")||"None"}</p>${sim}${crunch}${fit}`;analysisSet(tradeAnalysisKey(),{timestamp:Date.now(),html});out.innerHTML=html}
function evaluateManagerFit(m,offered,requested,managerDelta){if(!m)return"";const highly=namesMatching(offered,splitProfileTerms(m.playersHighlyValue)),favorites=namesMatching(offered,splitProfileTerms(m.favoriteProspects)),types=typeMatches(offered,splitProfileTerms(m.preferredPlayerTypes)),window=windowMatches(offered,m.competitiveWindow),importedLikes=namesMatching(offered,managerReceivedNames(m));const prefHits=new Set([...highly,...favorites,...types,...window,...importedLikes]);let prefScore=Math.min(100,20+highly.length*22+favorites.length*18+types.length*14+window.length*10+importedLikes.length*16+(prefHits.size?8:0));const valueScore=Math.max(0,Math.min(100,50+managerDelta*2));const reliance=m.hkbReliance||"Medium",valueWeight=reliance==="High"?.55:reliance==="Low"?.25:.4,prefWeight=1-valueWeight;let score=Math.round(valueScore*valueWeight+prefScore*prefWeight);score=Math.max(0,Math.min(100,score));const prob=score>=70?"High":score>=45?"Medium":"Low",ctx={score,prob,managerDelta,highly,favorites:[...favorites,...importedLikes],types,window},bullets=[];if(highly.length)bullets.push(`Offer includes players they highly value: ${highly.map(esc).join(", ")}.`);else bullets.push("No direct match to Players They Highly Value.");if(favorites.length)bullets.push(`Offer includes favorite prospect targets: ${favorites.map(esc).join(", ")}.`);if(importedLikes.length)bullets.push(`Imported history says they have acquired similar/named players: ${importedLikes.map(esc).join(", ")}.`);if(types.length)bullets.push(`Matches preferred player types with ${types.map(esc).join(", ")}.`);else bullets.push("Limited match to preferred player types.");if(window.length)bullets.push(`${esc(m.competitiveWindow)} window fit: ${window.map(esc).join(", ")}.`);else bullets.push(`Offer is light for a ${esc(m.competitiveWindow)} profile.`);bullets.push(reliance==="High"?`High HKB reliance: value balance weighs heavily, and their side is ${managerDelta>=0?"ahead":"behind"} by ${Math.abs(managerDelta).toFixed(1)} trade value.`:reliance==="Low"?`Low HKB reliance: manager preferences matter more than raw value here.`:`Medium HKB reliance: value balance and preference fit both matter.`);if(managerDelta<-8)bullets.push("Raw value gap may make acceptance harder.");return`<div class="manager-fit"><h3>Manager Fit Score: ${score}/100</h3><p><b>Acceptance Probability:</b> ${prob}</p><ul>${bullets.slice(0,6).map(b=>`<li>${b}</li>`).join("")}</ul></div>${buildNegotiationAssistant(m,offered,requested,ctx)}`}
const analyzeTradeImmediate=analyzeTradeDetailed;analyzeTrade=function(){showViewLoading("trade","Running trade impact simulation...");requestWorkerSummary("trade");setTimeout(analyzeTradeImmediate,20)}
