masterPlayerEngineFinish=function(started,opts={}){updatePortfolioScores();masterAssignRanks();waiverAlternativeCache=buildWaiverAlternativeCache();const settings=leagueSettings(),il=ilPlayers(),active=activeReservePlayers();rosterPressureCalcContext={full:il.length>=num(settings.roster?.maxIL,10),activeCount:active.length,limit:num(settings.roster?.maxTotal,33)};(db.players||[]).forEach(p=>{if(isWaiverAvailable(p))masterStoredWaiverScore(p,waiverFinderScore(p));masterStoredMarketEdge(p,marketEdgeAnalysis(p));if(isMine(p))masterStoredRosterPressure(p,rosterPressureDecision(p));p.activationPressureScore=activationPressureForPlayer(p);masterPlayerCanonicalize(p)});console.log("Player Engine scores updated");waiverAlternativeCache=null;rosterPressureCalcContext=null;db.settings=db.settings||{};db.settings.lastCalculationDurationMs=Date.now()-started;db.settings.lastFullRecalculationTimestamp=new Date().toISOString();db.settings.lastPlayerEngineRecalculatedPlayers=(db.players||[]).length;db.settings.lastFailedCalculationError="";db.settings.masterPlayerEngineKey=masterPlayerEngineKey();persistScoreCache();saveMasterPlayers();scoreRecalcPending=false;masterEngineRunning=false;if(opts.manual)setEngineButtonState(false);saveDB(false);renderMetrics();renderPerformanceControls();if(opts.render!==false)renderActiveView();const status=opts.statusEl||document.getElementById("scoreStatus");setEngineStatus(status,engineProgressHTML(db.players.length,db.players.length,started,true));if(currentView()==="help")renderHelpWorkflow();console.log(`Player Engine finished recalculation: ${db.players.length} players in ${db.settings.lastCalculationDurationMs} ms`);if(opts.showToast!==false)toast("Player Engine recalculated")}
masterPlayerEngineRecalculate=function(reason="manual",opts={}){if(masterEngineRunning){const status=opts.statusEl||document.getElementById("scoreStatus");setEngineStatus(status,"Player Engine is already recalculating...");return}const status=opts.statusEl||document.getElementById("scoreStatus"),players=db.players||[],started=Date.now();console.log(`Player Engine start recalculation (${reason})`);console.log(`Player Engine player count processed: 0 / ${players.length}`);masterEngineRunning=true;scoreRecalcPending=true;if(opts.manual)setEngineButtonState(true);setEngineStatus(status,engineProgressHTML(0,players.length,started));batchProcess(players,25,p=>masterPlayerEngineScoreOne(p),()=>{try{masterPlayerEngineFinish(started,opts)}catch(e){scoreRecalcPending=false;masterEngineRunning=false;if(opts.manual)setEngineButtonState(false);console.error("Player Engine recalculation failed",e);recordCalculationError(e,"Master Player Engine");renderPerformanceControls();setEngineStatus(status,engineProgressHTML(0,players.length,started,false,e.message));toast("Player Engine recalculation failed")}},(done,total)=>{console.log(`Player Engine player count processed: ${done} / ${total}`);setEngineStatus(status,engineProgressHTML(done,total,started))})}
function engineRunMeta(players,started){return{started,total:players.length,processed:0,skipped:0,errors:0,currentStep:"Loading players",currentPlayer:"",firstFailed:null,skippedSamples:[],failedSamples:[]}}
function engineLogSkip(ctx,p,index,reason){ctx.skipped++;const label=(p&&p.name)||`row ${index+1}`;const sample={player:label,reason};if(ctx.skippedSamples.length<10){ctx.skippedSamples.push(sample);console.warn("Player Engine skipped player",sample)}}
function engineLogError(ctx,p,index,step,error){ctx.errors++;const label=(p&&p.name)||`row ${index+1}`;if(!ctx.firstFailed){ctx.firstFailed={player:label,step,error};console.error("Player Engine first failed player",ctx.firstFailed)}console.error(`Player Engine player error during ${step}: ${label}`,error)}
function engineSafeHkb(p){const raw=p.hkbValue,clean=String(raw??"").trim();if(raw===null||raw===undefined||clean===""||!Number.isFinite(num(raw,NaN)))p.hkbValue=0;else p.hkbValue=num(raw)}
engineProgressHTML=function(done,total,started,complete=false,error="",meta={}){const step=meta.currentStep||ENGINE_PROGRESS_STEPS[Math.min(ENGINE_PROGRESS_STEPS.length-1,complete?ENGINE_PROGRESS_STEPS.length-1:1)],activeIndex=complete?ENGINE_PROGRESS_STEPS.length:Math.max(0,ENGINE_PROGRESS_STEPS.indexOf(step)),elapsed=((Date.now()-(started||Date.now()))/1000).toFixed(1),processed=meta.processed??done,skipped=meta.skipped||0,errors=meta.errors||0,player=meta.currentPlayer||"Preparing player batch",rows=ENGINE_PROGRESS_STEPS.map((s,i)=>{const doneStep=complete||i<activeIndex,mark=doneStep?"&#10003;":i===activeIndex?"...":"&middot;",cls=doneStep?"done":i===activeIndex?"active":"pending";return`<div class="engine-step ${cls}">${mark} ${esc(s)}...</div>`}).join("");return`<div class="engine-progress"><b>Player Engine</b><div class="engine-steps">${rows}</div><div class="engine-current"><div>Current step: ${esc(step)}</div><div>Current player: ${esc(player)}</div><div>Skipped: ${skipped} &bull; Errors: ${errors}</div></div>${error?`<div class="engine-error">Failed: ${esc(error)}</div>`:complete?`<div class="engine-complete">Completed in ${elapsed} seconds<br>${processed} players processed<br>${skipped} skipped &bull; ${errors} errors</div>`:`<div class="engine-complete">Recalculating... ${done} / ${total} players processed</div>`}</div>`}
function masterPlayerEngineScoreOneSafe(p,index,ctx){ctx.currentPlayer=(p&&p.name)||`row ${index+1}`;if(!p||!String(p.name||"").trim()){engineLogSkip(ctx,p,index,"Missing player name");return null}try{ctx.currentStep="Calculating HKB";engineSafeHkb(p);ctx.currentStep="Calculating Statcast";p.advancedBreakoutSignal=advancedBreakoutSignal(p);ctx.currentStep="Calculating Breakout Scores";scorePlayer(p);ctx.currentStep="Calculating Dynasty Asset Scores";p.roleSecurityScore=leagueRoleSecurity(p);p.weeklyReliabilityScore=statScore(num(p.currentValue)*.35+num(p.fantasyOpportunityScore)*.2+num(p.championshipImpactScore)*.22+num(p.pitcherRoleValueScore)*.12-num(p.dynastyRiskScore)*.14);ctx.processed++;return p}catch(e){engineLogError(ctx,p,index,ctx.currentStep,e);engineLogSkip(ctx,p,index,`Could not score during ${ctx.currentStep}`);return null}}
function engineFinishStep(ctx,label,fn){ctx.currentStep=label;try{return fn()}catch(e){ctx.errors++;console.error(`Player Engine step failed: ${label}`,e);if(!ctx.firstFailed){ctx.firstFailed={player:"Engine step",step:label,error:e};console.error("Player Engine first failed player",ctx.firstFailed)}return null}}
